import React from 'react';

const Projects = () => {
  const projects = [
    { institution: 'University A', degree: 'Bachelor of Science', year: '2018 - 2022' },
    { institution: 'School B', degree: 'High School', year: '2016 - 2018' },
  ];

  return (
    <section id="projects" className="projects">
      <h2>Projects</h2>
      <div>
        {projects.map((pro, index) => (
          <div key={index}>
            <h3>{pro.institution}</h3>
            <p>{pro.degree}</p>
            <p>{pro.year}</p>
          </div>
        ))}
      </div>
    </section>
  );
};

export default Projects;
